const input = $input.first().json.body || $input.first().json;

if (!input.job_id)        throw new Error('job_id required');
if (!input.user_id)       throw new Error('user_id required');
if (!input.apify_api_key) throw new Error('apify_api_key required');
if (!input.search_query)  throw new Error('search_query required');
if (!input.location)      throw new Error('location required');
if (!input.max_results)   throw new Error('max_results required');

return {
  job_id:        parseInt(input.job_id),
  user_id:       parseInt(input.user_id),
  apify_api_key: input.apify_api_key,
  search_query:  input.search_query,
  location:      input.location,
  max_results:   parseInt(input.max_results),
  apifyInput: {
    searchStringsArray:          [input.search_query],
    locationQuery:               input.location,
    maxCrawledPlacesPerSearch:   parseInt(input.max_results),
    language:                    'en',
    includeWebsites:             true,
    includeEmails:               true,
    includePhoneNumbers:         true
  }
};

