const response    = $input.first().json;
const prepareNode = $('Validate & Prepare Input').first().json;

if (response.error) {
  throw new Error('Apify start error: ' + JSON.stringify(response.error));
}

if (!response.data || !response.data.id) {
  throw new Error('Apify did not return a run ID');
}

return {
  runId:            response.data.id,
  defaultDatasetId: response.data.defaultDatasetId,
  apify_api_key:    prepareNode.apify_api_key,
  job_id:           prepareNode.job_id,
  user_id:          prepareNode.user_id,
  max_results:      prepareNode.max_results
};

const statusResponse = $input.first().json;
const prev           = $('Extract Run Info').first().json;

const status     = statusResponse.data?.status || 'UNKNOWN';
const isComplete = ['SUCCEEDED', 'FAILED', 'ABORTED'].includes(status);

return {
  runId:            prev.runId,
  defaultDatasetId: prev.defaultDatasetId,
  status:           status,
  isComplete:       isComplete,
  apify_api_key:    prev.apify_api_key,
  job_id:           prev.job_id,
  user_id:          prev.user_id,
  max_results:      prev.max_results
};

const data = $input.first().json;

if (data.status === 'FAILED' || data.status === 'ABORTED') {
  throw new Error(`Apify failed: ${data.status}`);
}

const prev = $('Extract Run Info').first().json;
const startTime = new Date(prev.startedAt || Date.now()).getTime();
const elapsed = Date.now() - startTime;

if (elapsed > 600000) {
  throw new Error('Apify timeout after 10 minutes');
}

return data;

const item      = $input.item.json;
const parseNode = $('Parse Status').first().json;

const raw = item;

const email =
  raw.email ||
  raw.emails?.[0] ||
  raw.contactEmail ||
  null;

const phone =
  raw.phone ||
  raw.phoneNumber ||
  raw.phones?.[0] ||
  null;

return {
  job_id:       parseNode.job_id,
  user_id:      parseNode.user_id,
  source:       'google_maps',
  raw_data:     raw,
  company_name: (raw.title || raw.name || 'Unknown').substring(0, 255),
  phone:        phone   ? String(phone).substring(0, 50)   : null,
  email:        email   ? String(email).substring(0, 255)  : null,
  website:      raw.website     ? raw.website.substring(0, 255)     : null,
  address:      raw.address     ? raw.address.substring(0, 500)     : null,
  city:         raw.city        ? raw.city.substring(0, 100)        : null,
  state:        raw.state       ? raw.state.substring(0, 100)       : null,
  zip:          raw.postalCode  || null,
  country:      raw.countryCode || null,
  category:     raw.categoryName ? raw.categoryName.substring(0, 100) : null
};

const items     = $input.all();
const parseNode = $('Parse Status').first().json;

if (items.length === 0) {
  return {
    bulk_values: null,
    job_id:  parseNode.job_id,
    user_id: parseNode.user_id,
    count:   0
  };
}

const values = items.map(item => {
  const r = item.json;
  const escape = (str) => str ? String(str).replace(/'/g, "''").substring(0, 255) : null;
  const raw = JSON.stringify(r.raw_data || r).replace(/'/g, "''");

  return `(
    ${r.job_id}, ${r.user_id}, 'google_maps',
    '${escape(r.company_name) || 'Unknown'}',
    ${r.phone   ? `'${escape(r.phone)}'`    : 'NULL'},
    ${r.email   ? `'${escape(r.email)}'`    : 'NULL'},
    ${r.website ? `'${escape(r.website)}'`  : 'NULL'},
    ${r.address ? `'${escape(r.address)}'`  : 'NULL'},
    ${r.city    ? `'${escape(r.city)}'`     : 'NULL'},
    ${r.state   ? `'${escape(r.state)}'`    : 'NULL'},
    ${r.zip     ? `'${escape(r.zip)}'`      : 'NULL'},
    ${r.country ? `'${escape(r.country)}'`  : 'NULL'},
    ${r.category? `'${escape(r.category)}'` : 'NULL'},
    '${raw}'::jsonb,
    'pending', false
  )`;
}).join(',\n');

return {
  bulk_values: values,
  job_id:  parseNode.job_id,
  user_id: parseNode.user_id,
  count:   items.length
};

const items     = $input.all();
const parseNode = $('Parse Status').first().json;

const leadCount  = items.length;
const actualCost = (leadCount / 100) * 0.01;

return {
  job_id:        parseNode.job_id,
  user_id:       parseNode.user_id,
  runId:         parseNode.runId,
  leads_scraped: leadCount,
  cost_usd:      actualCost
};
